import React, { createContext, useState, useContext, useEffect } from 'react';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [session, setSession] = useState(null); // Guardamos { token, user }
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const savedSession = localStorage.getItem('user-session');
        if (savedSession) {
            try {
                setSession(JSON.parse(savedSession));
            } catch (e) {
                localStorage.removeItem('user-session');
            }
        }
        setLoading(false);
    }, []);

    // Esta función ahora recibe los datos que ya obtuvo el Login.js
    const login = (userData) => {
        setSession(userData);
        localStorage.setItem('user-session', JSON.stringify(userData));
    };

    const logout = () => {
        setSession(null);
        localStorage.removeItem('user-session');
        localStorage.removeItem('active-cart');
        window.location.href = '/login';
    };

    return (
        <AuthContext.Provider value={{ 
            user: session?.user, // Esto entrega { id, nombre, rol, correo }
            token: session?.token, 
            isAuthenticated: !!session,
            login, 
            logout,
            loading 
        }}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);
